"""MetadataService for YAML persistence."""
import os
import yaml
from typing import Optional
from pathlib import Path

from agentcube.models.metadata import AgentMetadata


class MetadataService:
    """Service for loading and saving agent metadata."""

    @staticmethod
    def load_metadata(workspace: str) -> Optional[AgentMetadata]:
        """Load metadata from workspace."""
        metadata_path = Path(workspace) / "agent_metadata.yaml"
        if not metadata_path.exists():
            return None

        with open(metadata_path, "r") as f:
            data = yaml.safe_load(f)

        if data is None:
            return None

        return AgentMetadata(**data)

    @staticmethod
    def save_metadata(workspace: str, metadata: AgentMetadata) -> str:
        """Save metadata to workspace."""
        metadata_path = Path(workspace) / "agent_metadata.yaml"

        data = metadata.model_dump(exclude_none=True)

        with open(metadata_path, "w") as f:
            yaml.dump(data, f, default_flow_style=False, indent=2, sort_keys=False)

        return str(metadata_path)

    @staticmethod
    def metadata_exists(workspace: str) -> bool:
        """Check if metadata exists in workspace."""
        metadata_path = Path(workspace) / "agent_metadata.yaml"
        return metadata_path.exists()

"""PackRuntime for workspace validation."""
import os
from pathlib import Path
from typing import Tuple, List


class PackRuntime:
    """Runtime for validating agent workspace."""

    @staticmethod
    def validate_workspace(workspace: str, language: str) -> Tuple[bool, str]:
        """Validate workspace exists and contains required files."""
        workspace_path = Path(workspace)

        # Check directory exists
        if not workspace_path.exists():
            return False, f"Workspace '{workspace}' does not exist"

        if not workspace_path.is_dir():
            return False, f"Workspace '{workspace}' is not a directory"

        # Language-specific validation
        if language.lower() == "python":
            return PackRuntime._validate_python_workspace(workspace_path)
        elif language.lower() == "java":
            return PackRuntime._validate_java_workspace(workspace_path)
        elif language.lower() == "go":
            return PackRuntime._validate_go_workspace(workspace_path)
        elif language.lower() == "javascript" or language.lower() == "typescript":
            return PackRuntime._validate_node_workspace(workspace_path)

        return True, "Workspace validated"

    @staticmethod
    def _validate_python_workspace(workspace: Path) -> Tuple[bool, str]:
        """Validate Python workspace has at least one .py file."""
        py_files = list(workspace.glob("*.py"))
        if not py_files:
            return False, "Python workspace requires at least one .py file"
        return True, "Python workspace validated"

    @staticmethod
    def _validate_java_workspace(workspace: Path) -> Tuple[bool, str]:
        """Validate Java workspace has pom.xml."""
        pom_file = workspace / "pom.xml"
        if not pom_file.exists():
            return False, "Java workspace requires pom.xml"
        return True, "Java workspace validated"

    @staticmethod
    def _validate_go_workspace(workspace: Path) -> Tuple[bool, str]:
        """Validate Go workspace has go.mod."""
        go_mod = workspace / "go.mod"
        if not go_mod.exists():
            return False, "Go workspace requires go.mod"
        return True, "Go workspace validated"

    @staticmethod
    def _validate_node_workspace(workspace: Path) -> Tuple[bool, str]:
        """Validate Node.js workspace has package.json."""
        package_json = workspace / "package.json"
        if not package_json.exists():
            return False, "Node.js workspace requires package.json"
        return True, "Node.js workspace validated"

    @staticmethod
    def generate_dockerfile(workspace: str, language: str, entrypoint: str, port: int) -> str:
        """Generate Dockerfile for the agent."""
        dockerfile_path = Path(workspace) / "Dockerfile"

        if language.lower() == "python":
            content = PackRuntime._generate_python_dockerfile(entrypoint, port)
        elif language.lower() == "java":
            content = PackRuntime._generate_java_dockerfile(entrypoint, port)
        elif language.lower() == "go":
            content = PackRuntime._generate_go_dockerfile(entrypoint, port)
        elif language.lower() == "javascript" or language.lower() == "typescript":
            content = PackRuntime._generate_node_dockerfile(entrypoint, port)
        else:
            content = PackRuntime._generate_generic_dockerfile(entrypoint, port)

        with open(dockerfile_path, "w") as f:
            f.write(content)

        return str(dockerfile_path)

    @staticmethod
    def _generate_python_dockerfile(entrypoint: str, port: int) -> str:
        if not entrypoint:
            entrypoint = "app.py"
        return f'''FROM python:3.11-slim

WORKDIR /app

COPY requirements.txt .
RUN pip install --no-cache-dir -r requirements.txt

COPY . .

EXPOSE {port}

CMD ["python", "{entrypoint}"]
'''

    @staticmethod
    def _generate_java_dockerfile(entrypoint: str, port: int) -> str:
        return f'''FROM maven:3.9-eclipse-temurin-17-alpine AS build

WORKDIR /app
COPY pom.xml .
RUN mvn dependency:go-offline

COPY src ./src
RUN mvn package -DskipTests

FROM eclipse-temurin:17-jre-alpine

WORKDIR /app
COPY --from=build /app/target/*.jar app.jar

EXPOSE {port}

ENTRYPOINT ["java", "-jar", "app.jar"]
'''

    @staticmethod
    def _generate_go_dockerfile(entrypoint: str, port: int) -> str:
        if not entrypoint:
            entrypoint = "."
        return f'''FROM golang:1.22-alpine AS build

WORKDIR /app
COPY go.mod go.sum ./
RUN go mod download

COPY . .
RUN go build -o app {entrypoint}

FROM alpine:latest

WORKDIR /app
COPY --from=build /app/app .

EXPOSE {port}

CMD ["./app"]
'''

    @staticmethod
    def _generate_node_dockerfile(entrypoint: str, port: int) -> str:
        if not entrypoint:
            entrypoint = "index.js"
        return f'''FROM node:20-alpine

WORKDIR /app

COPY package*.json ./
RUN npm ci --only=production

COPY . .

EXPOSE {port}

CMD ["node", "{entrypoint}"]
'''

    @staticmethod
    def _generate_generic_dockerfile(entrypoint: str, port: int) -> str:
        return f'''FROM alpine:latest

WORKDIR /app

COPY . .

EXPOSE {port}

CMD ["./{entrypoint}"]
'''

"""Invoke command implementation."""
import json
import typer
from pathlib import Path
from typing import Optional, List
from rich.console import Console
from rich.panel import Panel
import requests

from agentcube.services.metadata import MetadataService
from agentcube.models.metadata import AgentMetadata

app = typer.Typer(help="Invoke agent endpoint")
console = Console()


@app.command()
def invoke(
    workspace: Optional[str] = typer.Option(".", "--workspace", help="Workspace directory"),
    payload: str = typer.Option("{}", "--payload", help="JSON payload"),
    header: Optional[List[str]] = typer.Option(None, "--header", help="Custom headers (key:value)"),
    provider: str = typer.Option("agentcube", "--provider", help="Provider (agentcube, k8s)"),
    verbose: bool = typer.Option(False, "--verbose", "-v", help="Verbose output"),
):
    """POST JSON to agent endpoint."""

    console.print(Panel.fit("[bold blue]AgentCube Invoke[/bold blue]"))

    # Load metadata
    metadata = MetadataService.load_metadata(workspace)
    if not metadata:
        console.print(f"[red]Error: No metadata found in workspace '{workspace}'[/red]")
        raise typer.Exit(code=1)

    # Validate payload is JSON
    try:
        json_payload = json.loads(payload)
    except json.JSONDecodeError as e:
        console.print(f"[red]Error: Invalid JSON payload: {e}[/red]")
        raise typer.Exit(code=1)

    # Parse headers
    headers = {}
    if header:
        for h in header:
            parts = h.split(":", 1)
            if len(parts) != 2:
                console.print(f"[red]Error: Invalid header format '{h}'. Expected 'key:value'[/red]")
                raise typer.Exit(code=1)
            headers[parts[0].strip()] = parts[1].strip()

    # Determine endpoint URL
    url = _get_endpoint_url(metadata, provider)
    if not url:
        console.print(f"[red]Error: Could not determine endpoint URL[/red]")
        raise typer.Exit(code=1)

    # Add session header if available
    if metadata.session_id:
        headers["X-AgentCube-Session-Id"] = metadata.session_id

    if verbose:
        console.print(f"[blue]Sending request to: {url}[/blue]")
        console.print(f"[blue]Headers: {headers}[/blue]")
        console.print(f"[blue]Payload: {json.dumps(json_payload, indent=2)}[/blue]")

    # Make request
    try:
        response = requests.post(
            url,
            json=json_payload,
            headers=headers,
            timeout=30
        )

        console.print(f"[green]Response:[/green]")
        console.print(f"  Status: {response.status_code}")

        try:
            response_json = response.json()
            console.print(json.dumps(response_json, indent=2))
        except:
            console.print(response.text)

        if response.status_code >= 400:
            raise typer.Exit(code=1)

    except requests.exceptions.RequestException as e:
        console.print(f"[red]Request failed: {e}[/red]")
        raise typer.Exit(code=1)


def _get_endpoint_url(metadata: AgentMetadata, provider: str) -> Optional[str]:
    """Get endpoint URL based on provider."""
    if provider == "agentcube":
        # For AgentRuntime with k8s_deployment.type == "AgentRuntime"
        if metadata.k8s_deployment and metadata.k8s_deployment.type == "AgentRuntime":
            if metadata.router_url and metadata.agent_name and metadata.k8s_deployment.namespace:
                return f"{metadata.router_url}/v1/namespaces/{metadata.k8s_deployment.namespace}/agent-runtimes/{metadata.agent_name}/invocations/"
        # Fallback to router_url
        if metadata.router_url:
            return metadata.router_url
    elif provider == "k8s":
        if metadata.k8s_deployment and metadata.k8s_deployment.service_url:
            return metadata.k8s_deployment.service_url

    return None


if __name__ == "__main__":
    app()

"""StatusRuntime for status checks."""
from typing import Dict, Optional
from agentcube.models.metadata import AgentMetadata


class StatusRuntime:
    """Runtime for checking agent status."""

    def get_status(self, metadata: AgentMetadata, provider: str) -> Dict:
        """Get status info for the agent."""
        if provider == "agentcube":
            return self._get_agentcube_status(metadata)
        elif provider == "k8s":
            return self._get_k8s_status(metadata)
        else:
            return {"status": "error", "message": f"Unknown provider: {provider}"}

    def _get_agentcube_status(self, metadata: AgentMetadata) -> Dict:
        """Get status from AgentCube."""
        if metadata.k8s_deployment and metadata.k8s_deployment.namespace and metadata.agent_name:
            return self._get_cr_k8s_status(metadata.agent_name, metadata.k8s_deployment.namespace)

        return {
            "status": "unknown",
            "endpoint": metadata.router_url or "N/A"
        }

    def _get_k8s_status(self, metadata: AgentMetadata) -> Dict:
        """Get status from Kubernetes."""
        if metadata.k8s_deployment and metadata.k8s_deployment.namespace and metadata.agent_name:
            return self._get_cr_k8s_status(metadata.agent_name, metadata.k8s_deployment.namespace)

        return {
            "status": "unknown",
            "endpoint": metadata.k8s_deployment.service_url if metadata.k8s_deployment else "N/A"
        }

    def _get_cr_k8s_status(self, agent_name: str, namespace: str) -> Dict:
        """
        Read from cr_object["status"] if present.
        Returns: status, agentEndpoint or "created_no_status" or "not_found_in_k8s"
        """
        # In a real implementation, this would query Kubernetes
        # For now, return a placeholder status
        return {
            "status": "running",
            "endpoint": f"http://{agent_name}.{namespace}.svc.cluster.local",
            "message": "Agent is running"
        }

"""InvokeRuntime for HTTP calls."""
from typing import Dict, Optional
import requests
from agentcube.models.metadata import AgentMetadata


class InvokeRuntime:
    """Runtime for invoking agents."""

    def invoke(self, metadata: AgentMetadata, payload: Dict, headers: Dict, provider: str) -> Dict:
        """Invoke the agent with given payload."""
        url = self._get_endpoint_url(metadata, provider)
        if not url:
            raise ValueError("Could not determine endpoint URL")

        # Add session header if available
        if metadata.session_id:
            headers["X-AgentCube-Session-Id"] = metadata.session_id

        response = requests.post(url, json=payload, headers=headers, timeout=30)

        return {
            "status_code": response.status_code,
            "body": response.json() if response.headers.get('content-type', '').startswith('application/json') else response.text
        }

    def _get_endpoint_url(self, metadata: AgentMetadata, provider: str) -> Optional[str]:
        """Get endpoint URL based on provider."""
        if provider == "agentcube":
            # For AgentRuntime with k8s_deployment.type == "AgentRuntime"
            if metadata.k8s_deployment and metadata.k8s_deployment.type == "AgentRuntime":
                if metadata.router_url and metadata.agent_name and metadata.k8s_deployment.namespace:
                    return f"{metadata.router_url}/v1/namespaces/{metadata.k8s_deployment.namespace}/agent-runtimes/{metadata.agent_name}/invocations/"
            # Fallback to router_url
            if metadata.router_url:
                return metadata.router_url
        elif provider == "k8s":
            if metadata.k8s_deployment and metadata.k8s_deployment.service_url:
                return metadata.k8s_deployment.service_url

        return None

"""Standard k8s Deployment+Service provider."""
from typing import Dict, Optional
import time
import uuid
from kubernetes import client, config
from kubernetes.client.rest import ApiException
from rich.console import Console

from agentcube.models.metadata import AgentMetadata

console = Console()


class KubernetesProvider:
    """Provider for standard Kubernetes deployments."""

    def __init__(self):
        self._init_k8s()

    def _init_k8s(self):
        """Initialize Kubernetes client."""
        try:
            config.load_incluster_config()
        except:
            try:
                config.load_kube_config()
            except:
                console.print("[yellow]Warning: Could not load Kubernetes config[/yellow]")

        self.apps_v1 = client.AppsV1Api()
        self.core_v1 = client.CoreV1Api()

    def deploy_agent(self, metadata: AgentMetadata, node_port: Optional[int], 
                     replicas: Optional[int], namespace: Optional[str]) -> Dict:
        """
        Deploy agent to Kubernetes.

        Returns: deployment_name, service_name, namespace, replicas, container_port, node_port, service_url
        """
        ns = namespace or "default"
        deployment_name = f"{metadata.agent_name}-deployment"
        service_name = f"{metadata.agent_name}-service"
        replicas_count = replicas or 1
        container_port = metadata.port or 8080

        # Create Deployment
        deployment = client.V1Deployment(
            api_version="apps/v1",
            kind="Deployment",
            metadata=client.V1ObjectMeta(
                name=deployment_name,
                labels={"app": metadata.agent_name}
            ),
            spec=client.V1DeploymentSpec(
                replicas=replicas_count,
                selector=client.V1LabelSelector(
                    match_labels={"app": metadata.agent_name}
                ),
                template=client.V1PodTemplateSpec(
                    metadata=client.V1ObjectMeta(
                        labels={"app": metadata.agent_name}
                    ),
                    spec=client.V1PodSpec(
                        containers=[client.V1Container(
                            name=metadata.agent_name,
                            image=metadata.image_url or f"{metadata.agent_name}:{metadata.version}",
                            ports=[client.V1ContainerPort(container_port=container_port)],
                            env=[client.V1EnvVar(name=k, value=v) 
                                 for k, v in (metadata.env_vars or {}).items()]
                        )]
                    )
                )
            )
        )

        try:
            self.apps_v1.create_namespaced_deployment(namespace=ns, body=deployment)
            console.print(f"[green]Created Deployment: {deployment_name}[/green]")
        except ApiException as e:
            if e.status == 409:
                # Deployment already exists, update it
                self.apps_v1.replace_namespaced_deployment(
                    name=deployment_name, namespace=ns, body=deployment
                )
                console.print(f"[green]Updated Deployment: {deployment_name}[/green]")
            else:
                raise

        # Create Service
        service = client.V1Service(
            api_version="v1",
            kind="Service",
            metadata=client.V1ObjectMeta(
                name=service_name,
                labels={"app": metadata.agent_name}
            ),
            spec=client.V1ServiceSpec(
                selector={"app": metadata.agent_name},
                ports=[client.V1ServicePort(
                    port=container_port,
                    target_port=container_port,
                    node_port=node_port
                )],
                type="NodePort" if node_port else "ClusterIP"
            )
        )

        try:
            self.core_v1.create_namespaced_service(namespace=ns, body=service)
            console.print(f"[green]Created Service: {service_name}[/green]")
        except ApiException as e:
            if e.status == 409:
                # Service already exists
                console.print(f"[green]Service already exists: {service_name}[/green]")
            else:
                raise

        # Get actual node port if assigned
        svc = self.core_v1.read_namespaced_service(name=service_name, namespace=ns)
        actual_node_port = None
        if svc.spec.ports:
            actual_node_port = svc.spec.ports[0].node_port

        # Build service URL
        service_url = f"http://{service_name}.{ns}.svc.cluster.local:{container_port}"

        return {
            "deployment_name": deployment_name,
            "service_name": service_name,
            "namespace": ns,
            "replicas": replicas_count,
            "container_port": container_port,
            "node_port": actual_node_port,
            "service_url": service_url
        }

    def wait_for_deployment_ready(self, name: str, namespace: str, timeout: int = 120):
        """
        Wait for deployment to be ready.

        Raises TimeoutError on timeout.
        """
        start_time = time.time()
        while time.time() - start_time < timeout:
            try:
                deployment = self.apps_v1.read_namespaced_deployment(name=name, namespace=namespace)
                if deployment.status.ready_replicas == deployment.status.replicas:
                    return
            except ApiException:
                pass
            time.sleep(2)

        raise TimeoutError(f"Deployment {name} did not become ready within {timeout}s")

    def delete_agent(self, name: str, namespace: str) -> Dict:
        """
        Delete agent from Kubernetes.

        Returns status, ignores 404.
        """
        deployment_name = f"{name}-deployment"
        service_name = f"{name}-service"

        try:
            self.apps_v1.delete_namespaced_deployment(
                name=deployment_name,
                namespace=namespace
            )
        except ApiException as e:
            if e.status != 404:
                raise

        try:
            self.core_v1.delete_namespaced_service(
                name=service_name,
                namespace=namespace
            )
        except ApiException as e:
            if e.status != 404:
                raise

        return {"status": "deleted"}

"""AgentRuntime CR provider."""
from typing import Dict
from kubernetes import client, config
from kubernetes.client.rest import ApiException
from rich.console import Console
import uuid

from agentcube.models.metadata import AgentMetadata

console = Console()


class AgentCubeProvider:
    """Provider for AgentRuntime CR."""

    def __init__(self):
        self._init_k8s()

    def _init_k8s(self):
        """Initialize Kubernetes client."""
        try:
            config.load_incluster_config()
        except:
            try:
                config.load_kube_config()
            except:
                console.print("[yellow]Warning: Could not load Kubernetes config[/yellow]")

        self.custom_api = client.CustomObjectsApi()

    def deploy_agent_runtime(self, metadata: AgentMetadata, namespace: str) -> Dict:
        """
        Creates AgentRuntime CR.

        Creates AgentRuntime CR with:
        - WORKLOAD_MANAGER_URL / ROUTER_URL in env_vars
        - sessionTimeout: "15m", maxSessionDuration: "8h"
        - imagePullSecrets: [{"name": "default-secret"}]
        """
        group = "runtime.agentcube.volcano.sh"
        version = "v1alpha1"
        plural = "agentruntimes"

        session_id = str(uuid.uuid4())

        agent_runtime = {
            "apiVersion": f"{group}/{version}",
            "kind": "AgentRuntime",
            "metadata": {
                "name": metadata.agent_name,
                "namespace": namespace,
                "labels": metadata.labels or {},
                "annotations": metadata.annotations or {}
            },
            "spec": {
                "targetPort": [
                    {
                        "pathPrefix": "/",
                        "port": metadata.port or 8080,
                        "protocol": "HTTP"
                    }
                ],
                "podTemplate": {
                    "spec": {
                        "containers": [
                            {
                                "name": metadata.agent_name,
                                "image": metadata.image_url or f"{metadata.agent_name}:{metadata.version}",
                                "ports": [
                                    {"containerPort": metadata.port or 8080}
                                ],
                                "env": [
                                    {"name": "WORKLOAD_MANAGER_URL", "value": metadata.workload_manager_url or ""},
                                    {"name": "ROUTER_URL", "value": metadata.router_url or ""},
                                    {"name": "SESSION_ID", "value": session_id}
                                ] + [{"name": k, "value": v} for k, v in (metadata.env_vars or {}).items()]
                            }
                        ],
                        "imagePullSecrets": [{"name": "default-secret"}]
                    }
                },
                "sessionTimeout": "15m",
                "maxSessionDuration": "8h"
            }
        }

        try:
            result = self.custom_api.create_namespaced_custom_object(
                group=group,
                version=version,
                namespace=namespace,
                plural=plural,
                body=agent_runtime
            )
            console.print(f"[green]Created AgentRuntime CR: {metadata.agent_name}[/green]")

            return {
                "agent_id": result["metadata"]["name"],
                "session_id": session_id,
                "status": "created",
                "namespace": namespace
            }

        except ApiException as e:
            if e.status == 409:
                # Already exists, update it
                result = self.custom_api.replace_namespaced_custom_object(
                    group=group,
                    version=version,
                    namespace=namespace,
                    plural=plural,
                    name=metadata.agent_name,
                    body=agent_runtime
                )
                console.print(f"[green]Updated AgentRuntime CR: {metadata.agent_name}[/green]")

                return {
                    "agent_id": result["metadata"]["name"],
                    "session_id": session_id,
                    "status": "updated",
                    "namespace": namespace
                }
            else:
                raise

"""PublishRuntime for deployment logic."""
from typing import Dict
from agentcube.models.metadata import AgentMetadata


class PublishRuntime:
    """Runtime for publishing agents."""

    def __init__(self):
        pass

    def publish(self, metadata: AgentMetadata, provider: str) -> Dict:
        """Publish agent to the specified provider."""
        if provider == "k8s":
            return self._publish_to_k8s(metadata)
        elif provider == "agentcube":
            return self._publish_to_agentcube(metadata)
        else:
            raise ValueError(f"Unknown provider: {provider}")

    def _publish_to_k8s(self, metadata: AgentMetadata) -> Dict:
        """Publish to Kubernetes."""
        from agentcube.providers.kubernetes_provider import KubernetesProvider

        provider = KubernetesProvider()
        return provider.deploy_agent(
            metadata,
            node_port=metadata.k8s_deployment.node_port if metadata.k8s_deployment else None,
            replicas=metadata.k8s_deployment.replicas if metadata.k8s_deployment else 1,
            namespace=metadata.k8s_deployment.namespace if metadata.k8s_deployment else "default"
        )

    def _publish_to_agentcube(self, metadata: AgentMetadata) -> Dict:
        """Publish to AgentCube."""
        from agentcube.providers.agentcube_provider import AgentCubeProvider

        provider = AgentCubeProvider()
        return provider.deploy_agent_runtime(
            metadata,
            namespace=metadata.k8s_deployment.namespace if metadata.k8s_deployment else "default"
        )
